INSERT INTO location_intro_bubbles
  (location_entity_id, lang, bubble_text, source, updated_at)
VALUES
  (201019, 'en', '@Ale & Eats — Warm lamplight spills across a dozen scarred tables, and the air carries the mingled scents of roasted meat, spilled ale, and ink from the back-room pigeonhole wall where @Meidri files adventurer reviews by house and species. A dragonewt with light-orange scale-dust on her forearms, she moves between the bar and the bulletin wall, amber eyes catching every coin-purse that changes hands. You could claim a table near the hearth and order a hot meal, or wander to the back to see what the Reviewers'' Bulletin holds.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'ru', '@Ale & Eats — В прокуренном зале пахнет тушёным мясом и старым деревом; двенадцать столов заняты наполовину, у стойки драконесса @Meidri протирает кружку, поглядывая на вход. На задней стене — та самая голубятня с ячейками: у каждой табличка с домом и видом, некоторые забиты свитками, пара пустует. Можно подойти к стойке, заказать горячее и перехватить @Meidri, пока она не ушла сортировать почту, или сразу двинуть к стене — полистать, что пишут об искателях приключений.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'uk', '@Ale & Eats — Дерев''яна двоповерхова споруда на південному боці площі Сталевої Брами, за два кроки від Гільдії та один від «Сміливої Кобили». Усередині дванадцять столів, довга стійка, кухня позаду і знаменита стіна з голубниками в задній кімнаті, де @Meidri розкладає відгуки про шукачів пригод за домівкою, видом і датою. Можна замовити гарячу страву, присісти біля стійки й переглянути свіжі записи, або ж підійти до стіни — можливо, там знайдеться щось корисне.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'bg', '@Ale & Eats — Вратата се отваря към топлата, наситена с аромат на хмел и печено месо въздушна смес на двуетажната дървена кръчма. Дванайсет маси са разположени около дългия бар, а отзад се чува тракането от кухнята. В дъното, зад завеса, се вижда прочутата стена с гълъбови ниши — „Рецензентският бюлетин“, където @Meidri подрежда свитъците с оценки за гилдиите и расите. Можеш да седнеш на маса и да поръчаш нещо топло, или да се приближиш до стената и да разгледаш последните рецензии.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'sr', '@Ale & Eats — У ову дрвену зграду на тргу Челичне капије улазиш у просторију испуњену мирисом хмеља и топлог јела. Дванаест столова је разбацано по приземљу, а иза дугачког шанка чује се звецкање из кухиње. На задњем зиду, чувени зид са преградама за гласове авантуриста чека да прегледаш нове белешке. Можеш да приђеш @Meidri за пиће или да завириш у тај зид.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'es', '@Ale & Eats — El rumor de la taberna te envuelve al cruzar la puerta: doce mesas de madera, una barra larga y el aroma a estofado que escapa de la cocina. Al fondo, la famosa pared de casilleros donde @Meidri archiva reseñas de aventureros por casa y especie. Puedes acercarte a la barra para pedir una jarra o dirigirte al tablón del fondo para ojear los informes.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'fr', '@Ale & Eats — Une odeur mêlée de bière brune et de ragoût d''orge vous accueille dans cette taverne à deux étages, sur la place du quartier Steelgate. Au fond, le mur de casiers en bois déborde de parchemins : c''est le tableau d''affichage des évaluateurs, où chaque maison et chaque espèce a son propre compartiment. La serveuse @Meidri, une dragonewt aux écailles orangées, trie les nouvelles fiches d''une main tout en essuyant un chope de l''autre. Vous pouvez vous installer à une table pour commander un plat chaud, ou vous approcher du mur pour consulter les dernières critiques d''aventuriers.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'de', '@Ale & Eats — Der warme Duft von geröstetem Brot und Hopfen schlägt dir entgegen, als du die Tür öffnest. Die Wirtsstube ist gut gefüllt, an der Theke unterhält sich die Drachengeborene @Meidri mit einem Gast, während ihre bernsteinfarbenen Augen kurz zu dir aufblicken. An der Rückwand fällt dein Blick auf das berühmte Taubenloch-Brett, in dessen Fächern handgeschriebene Bewertungen über Abenteurer aller Häuser und Spezies stecken. Du könntest dich an einen freien Tisch setzen und eine warme Mahlzeit bestellen oder zu Meidri gehen, um einen Blick auf die neuesten Einträge zu werfen.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'it', '@Ale & Eats — L''odore di stufato caldo e segatura si mescola al fumo delle candele mentre varchi la soglia di questa taverna a due piani, due porte più in là dalla Gilda. Al bancone, una dragonewt dalle squame arancio chiaro — @Meidri — sistema pile di pergamene con l''occhio vigile su chi entra. Dietro di lei, la famosa parete a casellari è gremita di recensioni d''avventurieri ordinate per gilda e specie. Puoi avvicinarti al banco per ordinare qualcosa di caldo, o dare un''occhiata ai messaggi infilati nei cubicoli di legno.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'pt', '@Ale & Eats — O cheiro de lúpulo e madeira envelhecida recebe-te ao entrares nesta taberna de dois andares, na praça do Bairro do Portão de Aço. À tua direita, a parede de pombais nos fundos está repleta de papéis — as avaliações de aventureiros que @Meidri, a dragonewt de escamas alaranjadas, organiza meticulosamente por casa e espécie. Podes pedir uma refeição quente ao balcão ou aproximar-te para folhear os relatos mais recentes.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'ro', '@Ale & Eats — Aerul cald te întâmpină cu miros de carne la grătar și ierburi proaspete. În spatele tejghelei, o dragonewtă cu solzi portocalii, @Meidri, aranjează teancuri de hârtii, iar pe peretele din spatele ei, un uriaș perete de porumbei este plin de suluri și bilete. Poți să te apropii de bar și să comanzi ceva de mâncare sau să arunci o privire mai atentă la peretele cu anunțuri.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'he', '@Ale & Eats — ריח של בירה חמוצה ולחם טרי מתערבבים עם עשן האח. על הקיר האחורי, לוח תיבות הדואר של הסוקרים מלא בפתקים צהובים, וקשקשת האור של מיידרי מנצנצת כשהיא ממיינת אותם. אפשר לשבת ליד הבר, להזמין ארוחה חמה, או לגשת למיידרי ולשאול על ההערות האחרונות.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'ar', '@Ale & Eats — تفوح رائحة الخبز الطازج والجعة الداكنة من هذه الحانة ذات الطابقين في ساحة ستيلغيت وورد. على الجانب الجنوبي، على بعد بابين من قاعة النقابة، تجد طاولات خشبية مكتظة ورفوفاً خلفية مليئة بأوراق التقييمات. يمكنك أن تسمع صوت ميدري، الساقية ذات القشور البرتقالية، وهي تنادي طلباً من المطبخ. يمكنك أن تأخذ مقعداً على البار أو تتجه نحو الجدار الخلفي لتصفح أحدث تقييمات المغامرين.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'fa', '@Ale & Eats — بوی خوش خوراک گرم و صدای لیوان‌ها از طبقهٔ همکف می‌آید؛ دوازده میز چوبی، بار بلند و دیوار پشتی پر از حفره‌های کبوتری که @Meidri نقدهای ماجراجویان را بر اساس خانه و گونه مرتب می‌کند. می‌توانی کنار بار بنشینی و یک غذای داغ سفارش دهی، یا به دیوار اعلانات نزدیک شوی تا ببینی کدام گروه تازه‌ترین بررسی‌ها را ثبت کرده‌اند.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'ur', '@Ale & Eats — لکڑی کے شہتیروں والی اس دو منزلہ سرائے میں بھنے ہوئے گوشت اور تازہ بیئر کی خوشبو گھلی ہوئی ہے۔ جنوبی دیوار کے ساتھ مشہور کبوترخانہ لگا ہے جس میں مہم جوؤں کے جائزے گھر اور نسل کے حساب سے ترتیب دیے گئے ہیں۔ آپ میڈری کو دیکھ سکتے ہیں جو اپنے نارنجی ترازو والے ہاتھوں سے کاغذات ترتیب دے رہی ہے۔ آپ بار پر جا کر گرم کھانے کا آرڈر دے سکتے ہیں یا پھر جائزوں کی دیوار کے قریب جا کر تازہ ترین اطلاعات دیکھ سکتے ہیں۔', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'hi', '@Ale & Eats — लकड़ी के इस दो-मंज़िला मधुशाला में बारह मेज़ें, एक लंबा बार, और पीछे रसोई है। दीवार पर लगे कबूतर-खाने में @Meidri साहसियों की समीक्षाएँ घर, प्रजाति और तारीख के हिसाब से रखती है। आप यहाँ गरम भोजन का ऑर्डर दे सकते हैं या पिछले कमरे में बुलेटिन बोर्ड देख सकते हैं।', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'mr', '@Ale & Eats — दोन मजली लाकडी इमारत, स्टीलगेट वॉर्डच्या चौकात गिल्डहॉलपासून दोन दरवाजे दूर. खाली बार, बारा टेबल्स आणि मागे स्वयंपाकघर. भिंतीवरच्या खाचांमध्ये @Meidri साहसी लोकांची पुनरावलोकने घर, जात आणि तारखेनुसार लावते. तुम्ही @Meidri कडे जाऊन नवीन पुनरावलोकन पाहू शकता किंवा @Guildhall of Belmorah कडे जाऊ शकता.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'ne', '@Ale & Eats — यो दुईतले काठको भवन स्टिलगेट वार्डको चोकको दक्षिणपट्टि अवस्थित छ, जहाँ तल्लो तल्लामा बाह्रवटा टेबल, लामो बार र भान्सा छ। पछाडिको कोठामा रहेको प्रसिद्ध परेवाको प्वाल भित्तामा @Meidri ले हरेक साहसीको समीक्षा घर, प्रजाति र मिति अनुसार फाइल गर्छिन्। तपाईंले यहाँ तातो खाना अर्डर गर्न सक्नुहुन्छ वा @Meidri सँग कुरा गरेर भर्खरको समीक्षा बुलेटिन हेर्न सक्नुहुन्छ।', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'bn', '@Ale & Eats — কাঠের মেঝেতে পায়ের শব্দ আর ভাজা মাংসের গন্ধ মিশে আছে। বারটেন্ডার @Meidri তার কমলা আঁশের বাহুতে স্তূপ করা খালি গ্লাস নিয়ে পায়রার খোপের দেওয়ালের দিকে তাকিয়ে আছে—সেখানে প্রতিটি অ্যাডভেঞ্চারারের রিভিউ বাড়ি, প্রজাতি আর তারিখ অনুযায়ী সাজানো। তুমি একটি খালি টেবিলে বসে গরম খাবারের অর্ডার দিতে পারো, অথবা @Meidri-এর কাছে গিয়ে দেওয়ালের খবর দেখতে পারো।', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'th', '@Ale & Eats — กลิ่นมอลต์และเนื้อตุ๋นอบเชยโชยมาปะทะจมูกทันทีที่ก้าวผ่านประตูไม้โอ๊คหนาๆ เข้าไปในห้องโถงชั้นล่าง โต๊ะไม้สิบสองตัวเรียงรายอยู่ใต้แสงเทียนสีเหลืองนวล ด้านหลังบาร์ยาวมีหญิงดรากอนนิวต์ผิวสีส้มอ่อนชื่อ @Meidri กำลังเช็ดแก้วด้วยผ้าขาว ข้างๆ เธอคือกำแพงตู้จดหมายขนาดใหญ่ที่เรียงรายด้วยช่องไม้เล็กๆ นับร้อย แต่ละช่องมีกระดาษโน้ตยื่นออกมา — บทวิจารณ์ของนักผจญภัยที่ถูกจัดเก็บตามบ้านและสายพันธุ์ คุณอาจเดินไปที่กำแพงตู้จดหมายเพื่ออ่านรีวิวล่าสุด หรือเดินไปที่บาร์เพื่อสั่งอาหารร้อนๆ สักจาน', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'el', '@Ale & Eats — Το ξύλινο διώροφο κτίριο στη νότια πλευρά της πλατείας της Σιδηροπύλης είναι γεμάτο ζεστασιά και βουητό. Δώδεκα τραπέζια, ένας μακρύς πάγκος και η μυρωδιά από το μαγειρείο του μάγειρα γεμίζουν τον χώρο. Στο βάθος, ο διάσημος τοίχος με τα περιστερώνα φιλοξενεί τις κριτικές των τυχοδιωκτών, ενώ η @Meidri, η δρακόσαυρα σερβιτόρα, τακτοποιεί φακέλους. Μπορείς να καθίσεις για ένα ζεστό γεύμα ή να ρίξεις μια ματιά στον πίνακα ανακοινώσεων.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'hy', '@Ale & Eats — Փայտե երկհարկանի շենքը լի է գարեջրի ու տաք կերակուրի հոտով, իսկ հետևի սենյակում գտնվող աղավնաբները լցված է արկածախնդիրների գրառումներով։ @Meidri-ն՝ թեփուկավոր թևերի բծերով դրագոնյուտը, կարգի է բերում թղթերը՝ հայացքը սրած դեպի դահլիճը։ Կարող ես մոտենալ բարին՝ պատվիրելու տաք ուտեստ, կամ ուսումնասիրել պատի գրառումները՝ տեսնելու, թե ով ինչ է գրել վերջին արշավանքների մասին։', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'ka', '@Ale & Eats — ხის ორსართულიანი შენობა, რომელიც ნახევრად ტავერნაა, ნახევრად საინფორმაციო ბიურო. თორმეტი მაგიდა, გრძელი ბარი, სამზარეულო უკანა მხარეს, და ცნობილი მტრედის ბუდეების კედელი, სადაც @Meidri ინახავს თითოეული ავანტიურისტის მიმოხილვას. ხის ხრაშუნი, ცხელი კერძების სუნი, და @Guildhall of Belmorah-ის მეზობლობა. შეგიძლიათ @Meidri-სთან მიახლოება ან კედლის დათვალიერება.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'ko', '@Ale & Eats — 나무 기둥과 낮은 천장 아래에서 맥주 향과 냄비 요리 냄새가 섞여 흐른다. 한쪽 벽면에는 비둘기칸이 빼곡히 박혀 있고, 각 칸마다 모험가 평가 기록이 종별, 종족별, 일자별로 정리되어 있다. 주인 Meidri가 바 뒤에서 서류 더미를 정리하며 손님들을 살피고 있다. 빈 테이블에 앉아 식사를 주문하거나, 비둘기칸 앞에 서서 최근 평가 기록을 훑어볼 수 있다.', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'ja', '@Ale & Eats — 木枠の梁が低く、暖炉の火が部屋の半分を照らす。カウンターの奥では鱗に明るい橙の粉をまとったドラゴニュートの女給仕、メイドリが、壁一面の仕切り棚に書類を整理している。冒険者の評価が種族や家ごとに仕分けられたその「鳩穴の壁」は、この店の心臓部だ。一杯の麦酒を頼みながら、最新の掲示を眺めてみるのもいいだろう。', 'ai_deepseek_location_intro_v1', now()),
  (201019, 'zh', '@Ale & Eats — 木梁低垂，炉火噼啪，麦酒与油脂的气息混着旧纸墨味。十二张桌子散落其间，吧台后厨铲叮当，而最引人注目的是后屋那面鸽巢墙——Meidri正倚在墙边，将一叠新评语按行会与种族塞入格口。你可以先到吧台要一杯暖身的麦酒，再踱到墙前翻翻那些写满冒险者口碑的纸条，或者找Meidri聊聊最近有什么值得注意的传闻。', 'ai_deepseek_location_intro_v1', now())
